export default {
  name: 'new',
  data () {
    return {
      saleShow: false,
      topShow: false,
      bottomShow: false,
      onePieceShow: false,
      homeWearShow: false,
      accessoryShow: false,
      items: []
    }
  },
  mounted(){
    fetch('.../items.json')
     .then(res => res.json())
     .then(items => (this.items = items))
  }

}
